import { useState } from "react";

function App() {
  const [resumeText, setResumeText] = useState("");
  const [result, setResult] = useState("");

  const analyzeResume = () => {
    if (resumeText.trim() === "") {
      setResult("Please paste your resume content first.");
    } else {
      setResult(
          "Resume analyzed successfully. Skills, strengths, and improvement areas will appear here."
      );
    }
  };

  return (
      <div
          style={{
            padding: "40px",
            fontFamily: "Arial",
            textAlign: "center",
          }}
      >
        <h1>AI Resume Analyzer </h1>

        <textarea
            placeholder="Paste your resume content here..."
            value={resumeText}
            onChange={(e) => setResumeText(e.target.value)}
            style={{
              width: "400px",
              height: "150px",
              padding: "10px",
            }}
        />

        <br /><br />

        <button onClick={analyzeResume}>Analyze Resume</button>

        <h3>Result:</h3>
        <p>{result}</p>
      </div>
  );
}

export default App;
